  padding: 16px;
  border: 1px solid rgba(34,34,34,0.12);
  border-radius: 18px;
  background: linear-gradient(180deg, rgba(34,34,34,0.04), rgba(34,34,34,0.015));
  text-align: center;
}
.wechat-mp-widget-image {
  display: block;
  width: 100%;
  max-width: 220px;
  margin: 0 auto;
  border-radius: 14px;
  box-shadow: 0 12px 28px rgba(34,34,34,0.08);
}
.wechat-mp-widget-name {
  margin: 12px 0 0;
  color: var(--text-color, #222);
  font-size: 15px;
  font-weight: 600;
  line-height: 1.5;
}
.wechat-mp-widget-desc {
  margin: 6px 0 0;
  color: rgba(34,34,34,0.6);
  font-size: 13px;
  line-height: 1.7;
}
.post-sidebar-wechat {
  margin-top: 22px;
  padding-top: 18px;
  border-top: 1px solid rgba(34,34,34,0.08);
  text-align: center;
}
.post-sidebar-wechat-image {
  display: block;
  width: 100%;
  max-width: 200px;
  margin: 0 auto;
  border-radius: 14px;
  box-shadow: 0 12px 28px rgba(34,34,34,0.08);
}
.post-sidebar-wechat-name {
  margin: 12px 0 0;
  color: var(--text-color, #222);
  font-size: 15px;
  font-weight: 600;
  line-height: 1.5;
}
.post-sidebar-wechat-desc {
  margin: 6px 0 0;
  color: rgba(34,34,34,0.6);
  font-size: 13px;
  line-height: 1.7;
}

.site-home-links {
  display: flex;
  justify-content: center;
  gap: 14px;
  margin: 18px 0 6px;
  flex-wrap: wrap;
  padding: 0 10px;
}
.site-lang-switch {
  display: flex;
  justify-content: center;
  margin: 0;
  width: 100%;
}
.site-lang-switch-link {
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  width: 100%;
  max-width: 220px;
  padding: 12px 16px;
  border: 1px solid rgba(34,34,34,0.16);
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(34,34,34,0.05), rgba(34,34,34,0.02));
  box-shadow: 0 10px 24px rgba(34,34,34,0.06);
  color: var(--text-color, #222);
  text-decoration: none;
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease;
}
.site-lang-switch-link:hover {
  border-color: rgba(34,34,34,0.28);
  box-shadow: 0 14px 30px rgba(34,34,34,0.1);
  text-decoration: none;
  transform: translateY(-1px);
}
.site-lang-switch-eyebrow {
  color: rgba(34,34,34,0.56);
  font-size: 11px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}
.site-lang-switch-label {
  margin-top: 4px;
  color: var(--text-color, #222);
  font-size: 15px;
  font-weight: 600;
  line-height: 1.4;
}
@media (max-width: 413px) {
  .site-home-links {
    gap: 10px;
    margin: 14px 0 2px;
    padding: 0 8px;
  }
  .site-lang-switch {
    width: 100%;
  }
  .site-lang-switch-link {
    width: 100%;
    max-width: 220px;
  }
}
